urlset:
{# Zola sitemap template - entries is provided by Zola with all pages and sections #}
{# Skip noindexed pages and generated source-record stubs (extra.source_id):
   keeping them out of the sitemap stops them diluting crawl budget and avoids
   advertising URLs we mark noindex. Mirrors the robots logic in partials/seo.html.
   Also skip machine-translated locales while the translation-dilution policy
   is on (Decision 15 / H1.4). Zola does NOT expose config.extra to the sitemap
   render context, so the locale list is inlined below — config.extra drives the
   robots meta in partials/seo.html, and this mirrors it. When the policy is
   lifted, revert BOTH: set config.extra.noindex_translations = false (robots)
   AND remove the _is_translation guard here (sitemap). #}
{% for sitemap_entry in entries %}
{%- set _is_translation = sitemap_entry.permalink is containing('/de/') or sitemap_entry.permalink is containing('/fr/') or sitemap_entry.permalink is containing('/es/') or sitemap_entry.permalink is containing('/ru/') or sitemap_entry.permalink is containing('/ja/') or sitemap_entry.permalink is containing('/ko/') or sitemap_entry.permalink is containing('/zh/') or sitemap_entry.permalink is containing('/zh-Hant/') or sitemap_entry.permalink is containing('/he/') -%}
{% if not sitemap_entry.extra.noindex and not sitemap_entry.extra.source_id and not _is_translation %}

        {{ sitemap_entry.permalink | safe }}
        {% if sitemap_entry.date %}
        {{ sitemap_entry.date | date(format="%Y-%m-%d") }}
        {% endif %}
        {% if sitemap_entry.permalink is containing('/wiki/') %}monthly{% elif sitemap_entry.permalink is containing('/timeline/') %}monthly{% elif sitemap_entry.permalink is containing('/articles/') %}weekly{% elif sitemap_entry.permalink is containing('/read/') %}monthly{% else %}weekly{% endif %}
        {% if sitemap_entry.permalink is matching("^https?://[^/]+/?$") %}1.0{% elif sitemap_entry.permalink is containing('/read/') %}0.9{% elif sitemap_entry.permalink is containing('/wiki/') %}0.7{% elif sitemap_entry.permalink is containing('/timeline/') %}0.7{% elif sitemap_entry.permalink is containing('/library/') %}0.7{% elif sitemap_entry.permalink is containing('/articles/') %}0.6{% else %}0.5{% endif %}
        {#- Add image if available in extra data -#}
        {%- if sitemap_entry.extra.image and sitemap_entry.extra.image is containing("/") -%}

            {% if sitemap_entry.extra.image is starting_with("http") %}{{ sitemap_entry.extra.image | safe }}{% else %}{{ get_url(path=sitemap_entry.extra.image) | safe }}{% endif %}
            {%- if sitemap_entry.extra.image_alt -%}
            {{ sitemap_entry.extra.image_alt | escape }}
            {%- endif -%}

        {%- endif -%}

{% endif %}
{% endfor %}
